export function CreditRebrandBadgeExternalImage({
  logoColor = LOGO_COLOR.DEFAULT,
  ...props
}: {
  logoColor?: $Values<typeof LOGO_COLOR>,
}): ComponentNode<SVGLogoProps> {
  const cdnUrl = getLogoCDNUrl(
    LOGO.CREDIT_REBRAND_BADGE,
    CREDIT_REBRAND_BADGE_COLORS,
    logoColor
  );

  return (
    <SVGLogo
      {...props}
      name={LOGO.CREDIT_REBRAND_BADGE}
      alt="PayPal Credit"
      role="presentation"
      logoColor={logoColor}
      cdnUrl={cdnUrl}
    />
  );
}

export function CreditRebrandBadgeInlineSVG({
  logoColor = LOGO_COLOR.DEFAULT,
  ...props
}: {
  logoColor?: $Values<typeof LOGO_COLOR>,
}): ComponentNode<SVGLogoProps> {
  const svg = getCreditRebrandBadgeSVG(
    getLogoColors(
      LOGO.CREDIT_REBRAND_BADGE,
      CREDIT_REBRAND_BADGE_COLORS,
      logoColor
    )
  );

  return (
    <SVGLogo
      {...props}
      name={LOGO.CREDIT_REBRAND_BADGE}
      alt="PayPal Credit"
      role="presentation"
      logoColor={logoColor}
      render={() => {
        return svg;
      }}
    />
  );
}

export const CreditRebrandBadge = CreditRebrandBadgeInlineSVG;

